  36→static inline float _sqrtfItem(float x)
  37→{
  38→    f64 _half = 0.5;
  39→
  40→    if (x > 0) {
  41→        vf32 y;
  42→        // returns an approximation to
  43→        f64 guess = __frsqrte(x);
  44→        // now have 12 sig bits
  45→        guess = 0.5 * guess * (3.0 - guess * guess * x);
  46→        // now have 24 sig bits
  47→        guess = 0.5 * guess * (3.0 - guess * guess * x);
  48→        // now have 32 sig bits
  49→        guess = 0.5 * guess * (3.0 - guess * guess * x);
  50→        y = x * guess;
  51→        return y;
  52→    }
  53→    return x;
  54→}
