  56→/// Apply Item Damage
  57→f32 it_8026B1D4(HSD_GObj* gobj, HitCapsule* itemHitboxUnk)
  58→{
  59→    f32 ret = itemHitboxUnk->damage;
  60→    const Item* ip = gobj->user_data;
  61→    if (ip->xDC8_word.flags.x14 != 0) {
  62→        f32 itemSpeed = _sqrtfItem(ip->x40_vel.x * ip->x40_vel.x +
  63→                                   ip->x40_vel.y * ip->x40_vel.y +
  64→                                   ip->x40_vel.z * ip->x40_vel.z);
  65→
  66→        ret += itemSpeed * it_804D6D28->x80_float[5];
  67→        ret += it_804D6D28->x80_float[6];
  68→        if (ret <= 1.0) {
  69→            return ret = 1;
  70→        }
  71→    }
  72→    return ret;
  73→}
