1104→/// Find the closest item to the given position?
1105→/// @remarks Used by Samus's Homing Missile to lock onto certain items.
1106→/// @returns The nearest #HSD_GObj to @p pos that fits the criteria.
1107→HSD_GObj* it_8026C258(Vec3* pos, f32 facing_dir)
1108→{
1109→    f32 min_sq_dist = F32_MAX;
1110→    HSD_GObj *cur, *result = NULL;
1111→    for (cur = HSD_GObj_Entities->items; cur != NULL; cur = cur->next) {
1112→        Item* ip = GET_ITEM(cur);
1113→
1114→        // Might not actually be (exclusively) hold kind in the end???
1115→        enum_t hold_kind = ip->hold_kind;
1116→
1117→        // Decide lock-on type for Samus Missile?
1118→        if ((hold_kind == ITEM_UNK_MATO || hold_kind == ITEM_UNK_LOCKON ||
1119→             /// @todo Why is this cast to @c short necessary?
1120→             (short) (hold_kind == ITEM_UNK_ENEMY) ||
1121→             hold_kind == ITEM_UNK_7) &&
1122→            ip->grab_victim == NULL &&
1123→            (!ip->xDC8_word.flags.x13 || ip->owner == NULL) &&
1124→            (facing_dir != -1 || !(ip->pos.x > pos->x)) &&
1125→            (facing_dir != +1 || !(ip->pos.x < pos->x)))
1126→        {
1127→            f32 dist_x = pos->x - ip->pos.x;
1128→            f32 dist_y = pos->y - ip->pos.y;
1129→            f32 sq_dist = dist_x * dist_x + dist_y * dist_y;
1130→
1131→            if (sq_dist < min_sq_dist) {
1132→                min_sq_dist = sq_dist;
1133→                result = cur;
1134→            }
1135→        }
1136→    }
1137→
1138→    return result;
1139→}
